python3 -c "
import os
base = '/home/mrsar/protein-ag/past-published-data/disease-relevant non-inhibited/'
# Find all fit.tsv files recursively (bounded)
results = []
for root, dirs, files in os.walk(base):
    for f in files:
        if f == 'fit.tsv':
            results.append(os.path.join(root, f))
print(f'Total fit.tsv: {len(results)}')
for p in results[:5]:
    print(p)
